+        while (iter.next() catch null) |entry| {
+            if (entry.kind == .file and std.mem.startsWith(u8, entry.name, "test_") and std.mem.endsWith(u8, entry.name, ".py")) {
+                const path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ test_dir, entry.name });
